using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly string[] _labels;

    public TicketsController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;

        // Extract label names from the model's output schema
        var engine = _predictionPool.GetPredictionEngine();
        var labelColumn = engine.OutputSchema.GetColumnOrNull("Score")
            ?? throw new InvalidOperationException("Score column not found in model schema.");
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.Value.GetSlotNames(ref slotNames);
        _labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    [HttpPost("classify")]
    public ActionResult<PredictResponse> Classify([FromBody] PredictRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_labels[i]] = prediction.Score[i];
        }

        return Ok(new PredictResponse
        {
            Category = prediction.Category,
            Confidence = confidence
        });
    }
}

